import{_ as l,c as e,o as i,ae as r}from"./chunks/framework.Dh1jimFm.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"client-doc/core/permission.md","filePath":"client-doc/core/permission.md","lastUpdated":1770358354000}'),o={name:"client-doc/core/permission.md"};function t(s,a,n,c,d,h){return i(),e("div",null,a[0]||(a[0]=[r('<h3 id="权限" tabindex="-1">权限 <a class="header-anchor" href="#权限" aria-label="Permalink to &quot;权限&quot;">​</a></h3><p>ENFI脚手架采用标准的RBAC（Role-Based Access Control）权限模型，提供完善的权限控制体系。</p><h4 id="rbac权限模型" tabindex="-1">RBAC权限模型 <a class="header-anchor" href="#rbac权限模型" aria-label="Permalink to &quot;RBAC权限模型&quot;">​</a></h4><p>基于经典的&quot;用户-角色-权限&quot;三层结构，实现灵活的权限分配与管理。</p><h4 id="权限注解使用" tabindex="-1">权限注解使用 <a class="header-anchor" href="#权限注解使用" aria-label="Permalink to &quot;权限注解使用&quot;">​</a></h4><p>框架提供简洁的权限控制注解，通过<code>@PreAuthorize</code>注解配合权限标识符实现接口级别的访问控制，支持细粒度的权限校验。</p><h4 id="权限数据表结构" tabindex="-1">权限数据表结构 <a class="header-anchor" href="#权限数据表结构" aria-label="Permalink to &quot;权限数据表结构&quot;">​</a></h4><p>系统通过五张核心表实现权限管理：</p><ol><li><strong>用户表（sys_user）</strong>：存储用户基本信息与状态</li><li><strong>角色表（sys_role）</strong>：定义角色属性与数据权限范围</li><li><strong>用户角色关联表（sys_user_role）</strong>：建立用户与角色的多对多关系</li><li><strong>菜单权限表（sys_menu）</strong>：管理系统菜单与操作权限标识</li><li><strong>角色菜单关联表（sys_role_menu）</strong>：建立角色与菜单权限的多对多关系</li></ol><h4 id="数据权限控制" tabindex="-1">数据权限控制 <a class="header-anchor" href="#数据权限控制" aria-label="Permalink to &quot;数据权限控制&quot;">​</a></h4><p>权限级别划分</p><p>系统支持多层次的数据权限控制，包括：</p><ul><li><strong>全部数据权限</strong>：可访问所有数据</li><li><strong>自定数据权限</strong>：自定义数据访问范围</li><li><strong>部门数据权限</strong>：仅限本部门数据</li><li><strong>部门及以下数据权限</strong>：本部门及其下属部门数据</li><li><strong>仅本人数据权限</strong>：仅限个人创建的数据</li></ul><h4 id="数据权限切面机制" tabindex="-1">数据权限切面机制 <a class="header-anchor" href="#数据权限切面机制" aria-label="Permalink to &quot;数据权限切面机制&quot;">​</a></h4><p>通过AOP切面技术实现数据权限的自动过滤，系统自动根据用户角色和数据权限配置，在数据查询时动态添加过滤条件，确保用户只能访问权限范围内的数据。</p><h4 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h4><p>精细化权限控制</p><ul><li>支持菜单级、按钮级、数据级的多维度权限控制</li><li>灵活的角色配置，支持多角色分配</li><li>实时权限验证，确保访问安全</li></ul><p>数据隔离保障</p><ul><li>基于部门架构的数据隔离</li><li>支持复杂的数据权限规则配置</li><li>防止越权数据访问</li></ul><p>灵活的扩展性</p><ul><li>支持自定义权限规则</li><li>可扩展的数据权限策略</li><li>易于集成的权限校验接口</li></ul><p>安全管理</p><ul><li>权限变更实时生效</li><li>操作日志记录与审计</li><li>防止权限提升攻击</li></ul><h4 id="应用优势" tabindex="-1">应用优势 <a class="header-anchor" href="#应用优势" aria-label="Permalink to &quot;应用优势&quot;">​</a></h4><p>ENFI框架的权限管理系统为企业应用提供了标准化、安全可靠的权限控制解决方案，显著减少了权限相关的开发工作量，同时确保系统的数据安全性和访问控制精确性。通过RBAC模型与数据权限的有机结合，满足企业级应用对权限管理的复杂需求。</p>',26)]))}const _=l(o,[["render",t]]);export{u as __pageData,_ as default};
